  useEffect(() => {
    return () => {
      // Final cleanup to ensure no memory leaks
      clearTimeoutRef(tooltipShowDelayTimerRef)
      clearTimeoutRef(tooltipHideDelayTimerRef)
      clearTimeoutRef(tooltipAutoCloseTimerRef)
      clearTimeoutRef(missedTransitionTimerRef)
    }
  }, [])

  const tooltipNode =
    rendered && !hidden && hasContent ? (
      <WrapperElement
        id={id}
        role={role}
        className={clsx(
          'react-tooltip',
          coreStyles['tooltip'],
          styles['tooltip'],
          styles[variant],
          className,
          `react-tooltip__place-${computedPosition.place}`,
          coreStyles[canShow ? 'show' : 'closing'],
          canShow ? 'react-tooltip__show' : 'react-tooltip__closing',
          positionStrategy === 'fixed' && coreStyles['fixed'],
          clickable && coreStyles['clickable'],
        )}
        onTransitionEnd={(event: TransitionEvent) => {
          clearTimeoutRef(missedTransitionTimerRef)
          if (show || event.propertyName !== 'opacity') {
            return
          }
          setRendered(false)
          setImperativeOptions(null)
          afterHide?.()
        }}
        style={tooltipStyle}
        ref={tooltipRef}
      >
        <WrapperElement
          className={clsx(
            'react-tooltip-content-wrapper',
            coreStyles['content'],
            styles['content'],
          )}
        >
          {actualContent}
        </WrapperElement>
        <WrapperElement
          className={clsx(
            'react-tooltip-arrow',
            coreStyles['arrow'],
            styles['arrow'],
            classNameArrow,
            noArrow && coreStyles['noArrow'],
          )}
          style={arrowStyle}
          ref={tooltipArrowRef}
        />
      </WrapperElement>
    ) : null

  if (!tooltipNode) {
    return null
  }

  if (portalRoot) {
    return createPortal(tooltipNode, portalRoot)
  }

